INSERT INTO question_bank (id, mission_id, question_type, prompt, options_json, source_type, is_active) VALUES
    ('aaaaaaa1-0000-0000-0000-000000000006', '11111111-1111-1111-1111-111111111111', 'OX', 'AI should never be checked by a human.', NULL, 'STATIC', TRUE),
    ('aaaaaaa1-0000-0000-0000-000000000007', '11111111-1111-1111-1111-111111111111', 'MULTIPLE', 'Which source is best for checking a science fact?', '["A trusted textbook or official site","A random rumor post","Only one anonymous comment"]', 'STATIC', TRUE),
    ('aaaaaaa1-0000-0000-0000-000000000008', '11111111-1111-1111-1111-111111111111', 'FILL', 'AI can help you brainstorm, but you should still use your own _____.', '["judgment","password","guess"]', 'STATIC', TRUE),
    ('aaaaaaa1-0000-0000-0000-000000000009', '11111111-1111-1111-1111-111111111111', 'SITUATION', 'AI gives two different answers to the same question. What should you do?', '["Compare both with reliable sources","Pick the longer one","Assume both are true"]', 'STATIC', TRUE),
    ('aaaaaaa1-0000-0000-0000-000000000010', '11111111-1111-1111-1111-111111111111', 'MULTIPLE', 'What kind of information should you avoid putting into AI?', '["Private personal data","A public math question","A book title"]', 'STATIC', TRUE),
    ('aaaaaaa2-0000-0000-0000-000000000006', '11111111-1111-1111-1111-111111111112', 'OX', 'A confident AI answer can still be wrong.', NULL, 'STATIC', TRUE),
    ('aaaaaaa2-0000-0000-0000-000000000007', '11111111-1111-1111-1111-111111111112', 'MULTIPLE', 'What should you compare when checking an AI answer?', '["Dates, names, and numbers","Only the length","Just the punctuation"]', 'STATIC', TRUE),
    ('aaaaaaa2-0000-0000-0000-000000000008', '11111111-1111-1111-1111-111111111112', 'FILL', 'Checking more than one source is called cross-_____.', '["checking","posting","guessing"]', 'STATIC', TRUE),
    ('aaaaaaa2-0000-0000-0000-000000000009', '11111111-1111-1111-1111-111111111112', 'SITUATION', 'Your friend wants to repost an AI-generated fact immediately. What is best?', '["Verify it first","Post it faster","Add more guesses"]', 'STATIC', TRUE),
    ('aaaaaaa2-0000-0000-0000-000000000010', '11111111-1111-1111-1111-111111111112', 'MULTIPLE', 'Which source is usually strongest for official rules?', '["An official organization website","A random chat room","A guessed summary"]', 'STATIC', TRUE),
    ('aaaaaaa3-0000-0000-0000-000000000006', '11111111-1111-1111-1111-111111111113', 'OX', 'A vague prompt usually gives a more precise answer.', NULL, 'STATIC', TRUE),
    ('aaaaaaa3-0000-0000-0000-000000000007', '11111111-1111-1111-1111-111111111113', 'MULTIPLE', 'Which prompt adds a clear format?', '["List 3 bullet points","Tell me something","Anything is fine"]', 'STATIC', TRUE),
    ('aaaaaaa3-0000-0000-0000-000000000008', '11111111-1111-1111-1111-111111111113', 'FILL', 'Telling AI who the answer is for helps define the target _____.', '["audience","server","password"]', 'STATIC', TRUE),
    ('aaaaaaa3-0000-0000-0000-000000000009', '11111111-1111-1111-1111-111111111113', 'SITUATION', 'The answer is too difficult for a child. What should you ask?', '["Use easier words for a younger student","Add private details","Make it unrelated"]', 'STATIC', TRUE),
    ('aaaaaaa3-0000-0000-0000-000000000010', '11111111-1111-1111-1111-111111111113', 'MULTIPLE', 'What improves a prompt the most?', '["A clear goal and constraints","Only one vague word","No context at all"]', 'STATIC', TRUE),
    ('bbbbbbb1-0000-0000-0000-000000000006', '22222222-2222-2222-2222-222222222221', 'OX', 'Adding an audience to a prompt can improve the answer.', NULL, 'STATIC', TRUE),
    ('bbbbbbb1-0000-0000-0000-000000000007', '22222222-2222-2222-2222-222222222221', 'MULTIPLE', 'Which prompt gives the clearest length requirement?', '["Explain it in exactly 4 sentences","Explain it well","Explain it soon"]', 'STATIC', TRUE),
    ('bbbbbbb1-0000-0000-0000-000000000008', '22222222-2222-2222-2222-222222222221', 'FILL', 'A follow-up prompt can help _____ the first answer.', '["refine","hide","ignore"]', 'STATIC', TRUE),
    ('bbbbbbb1-0000-0000-0000-000000000009', '22222222-2222-2222-2222-222222222221', 'SITUATION', 'The answer is correct but too long. What is the best next prompt?', '["Shorten it into 3 bullet points","Delete the topic","Add private data"]', 'STATIC', TRUE),
    ('bbbbbbb1-0000-0000-0000-000000000010', '22222222-2222-2222-2222-222222222221', 'MULTIPLE', 'What makes a prompt advanced?', '["Specific constraints and audience","No purpose","Only one unclear word"]', 'STATIC', TRUE)
INSERT INTO private.question_answer_keys (question_id, answer_payload, explanation) VALUES
    ('aaaaaaa1-0000-0000-0000-000000000006', '"false"', 'AI output should still be checked by a human.'),
    ('aaaaaaa1-0000-0000-0000-000000000007', '"A trusted textbook or official site"', 'Reliable sources are stronger than rumors.'),
    ('aaaaaaa1-0000-0000-0000-000000000008', '"judgment"', 'AI helps, but your own thinking still matters.'),
    ('aaaaaaa1-0000-0000-0000-000000000009', '"Compare both with reliable sources"', 'When answers conflict, verification matters even more.'),
    ('aaaaaaa1-0000-0000-0000-000000000010', '"Private personal data"', 'Private data should not be shared with AI tools.'),
    ('aaaaaaa2-0000-0000-0000-000000000006', '"true"', 'Confidence does not guarantee correctness.'),
    ('aaaaaaa2-0000-0000-0000-000000000007', '"Dates, names, and numbers"', 'These details are common fact-check targets.'),
    ('aaaaaaa2-0000-0000-0000-000000000008', '"checking"', 'Cross-checking means comparing multiple sources.'),
    ('aaaaaaa2-0000-0000-0000-000000000009', '"Verify it first"', 'Sharing unverified facts can spread errors.'),
    ('aaaaaaa2-0000-0000-0000-000000000010', '"An official organization website"', 'Official sites are best for official rules.'),
    ('aaaaaaa3-0000-0000-0000-000000000006', '"false"', 'Vague prompts usually reduce precision.'),
    ('aaaaaaa3-0000-0000-0000-000000000007', '"List 3 bullet points"', 'A clear output format improves usefulness.'),
    ('aaaaaaa3-0000-0000-0000-000000000008', '"audience"', 'Audience helps AI adjust tone and difficulty.'),
    ('aaaaaaa3-0000-0000-0000-000000000009', '"Use easier words for a younger student"', 'Good follow-ups refine clarity without changing topic.'),
    ('aaaaaaa3-0000-0000-0000-000000000010', '"A clear goal and constraints"', 'Goals and constraints make prompts stronger.'),
    ('bbbbbbb1-0000-0000-0000-000000000006', '"true"', 'Audience is a useful prompt constraint.'),
    ('bbbbbbb1-0000-0000-0000-000000000007', '"Explain it in exactly 4 sentences"', 'Exact length requirements improve specificity.'),
    ('bbbbbbb1-0000-0000-0000-000000000008', '"refine"', 'Follow-up prompts refine the first answer.'),
    ('bbbbbbb1-0000-0000-0000-000000000009', '"Shorten it into 3 bullet points"', 'A precise follow-up can improve format and brevity.'),
    ('bbbbbbb1-0000-0000-0000-000000000010', '"Specific constraints and audience"', 'Advanced prompts clearly constrain the result.')
